const i = $input.first() ? ($input.first().json || {}) : {};
function pick(){ for(var k=0;k<arguments.length;k++){ var v=arguments[k]; if(v!=null && String(v).trim()!=='') return String(v).trim(); } return ''; }
const txt = pick(i.text).replace(/^\/certificate\b/i,'').trim();
const name = pick(i['Recipient name'], i['Recipient'], i.name, txt) || 'Recipient Name';
const course = pick(i['Course / topic'], i['Course'], i.course, i.topic) || 'Cybersecurity Awareness';
let date = pick(i['Date'], i.date); if(!date) date = new Date().toISOString().slice(0,10);
let id = pick(i['Certificate ID'], i.id); if(!id) id = 'JAW-' + Date.now().toString(36).toUpperCase().slice(-6);
const safe = (name+'-'+course).toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'').slice(0,50) || 'certificate';
return [{ json: { name:name, course:course, date:date, certId:id, client:($env.CLIENT_NAME||'').toString(), fileSafe:safe, outDir:'certificates', filePrefix:'certificate' } }];

const j = $json || {};
function esc(s){ return (s==null?'':String(s)).replace(/[&<>]/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;'})[c];}); }
function ord(n){ var s=['th','st','nd','rd'],v=n%100; return n+(s[(v-20)%10]||s[v]||s[0]); }
function pretty(x){ try{ var p=String(x).split('-'); var dt=new Date(+p[0],+p[1]-1,+p[2]); var M=['January','February','March','April','May','June','July','August','September','October','November','December']; return M[dt.getMonth()]+' '+ord(dt.getDate())+' '+dt.getFullYear(); }catch(e){ return x; } }
const issuer = j.client ? j.client : 'Security Awareness Team';
const CSS = "@page{size:A4 landscape;margin:0} *{box-sizing:border-box} body{margin:0;font-family:Georgia,'Times New Roman',serif;color:#14202b} "
+".cert{height:100vh;padding:26px;background:#fff} .frame{height:100%;border:3px solid #0E7C86;border-radius:10px;position:relative;padding:46px 60px;text-align:center} "
+".frame:before{content:'';position:absolute;top:12px;left:12px;right:12px;bottom:12px;border:1px solid #C9A24B;border-radius:6px} "
+".kick{position:relative;letter-spacing:6px;font-size:14px;color:#0E7C86;font-weight:700;text-transform:uppercase;font-family:Arial} "
+"h1{position:relative;font-size:46px;margin:6px 0 4px;color:#0E2233} .sub{position:relative;font-style:italic;color:#5A6472;font-size:16px} "
+".name{position:relative;font-size:40px;color:#0E2233;margin:30px 0 8px;border-bottom:2px solid #C9A24B;display:inline-block;padding:0 30px 8px} "
+".course{position:relative;font-size:22px;color:#0E7C86;margin:18px 0} .course b{color:#0E2233} "
+".row{position:relative;display:flex;justify-content:space-between;align-items:flex-end;margin-top:54px;padding:0 20px} .sig{width:38%;border-top:1px solid #8a98a4;padding-top:8px;font-size:13px;color:#5A6472;font-family:Arial} "
+".id{position:absolute;bottom:18px;left:0;right:0;font-size:11px;color:#9aa6b2;font-family:Arial;letter-spacing:1px}";
const html = '<!doctype html><html><head><meta charset="utf-8"><style>'+CSS+'</style></head><body><div class="cert"><div class="frame">'
+'<div class="kick">Certificate of Completion</div>'
+'<h1>'+esc(issuer)+'</h1>'
+'<div class="sub">This is proudly presented to</div>'
+'<div class="name">'+esc(j.name)+'</div>'
+'<div class="sub">for successfully completing</div>'
+'<div class="course"><b>'+esc(j.course)+'</b></div>'
+'<div class="row"><div class="sig">'+esc(pretty(j.date))+'<br>Date</div><div class="sig">'+esc(issuer)+'<br>Issued by</div></div>'
+'<div class="id">Certificate ID: '+esc(j.certId)+' &middot; AI-generated — verify before issuing</div>'
+'</div></div></body></html>';
return [{ json: { html: html, topic: j.course, date: j.date, fileSafe: j.fileSafe, outDir: j.outDir, filePrefix: j.filePrefix } }];

const html = $json.html || '';
return [{ json: { topic:$json.topic, date:$json.date, fileSafe:$json.fileSafe, outDir:$json.outDir, filePrefix:$json.filePrefix },
  binary: { data: { data: Buffer.from(html,'utf8').toString('base64'), mimeType:'text/html', fileName:'index.html' } } }];

const fs = require('fs');
const meta = $('Render HTML').first().json;
const dir = '/reports/awareness/' + (meta.outDir || 'misc');
const name = (meta.filePrefix || 'asset') + '-' + (meta.fileSafe || 'item') + '-' + meta.date + '.pdf';
let buf = null;
try { buf = await this.helpers.getBinaryDataBuffer(0, 'data'); } catch (e) {}
try { fs.mkdirSync(dir, { recursive: true }); if (buf) fs.writeFileSync(dir + '/' + name, buf); } catch (e) {}
const out = { json: { ok: !!buf, file: dir + '/' + name, topic: meta.topic } };
try { const b = $input.first().binary; if (b && b.data) { b.data.fileName = name; out.binary = { data: b.data }; } } catch (e) {}
return [out];
